#include <stdio.h>
#include <stdint.h>

/* Simulated Interrupt Descriptor Table */
typedef struct {
    uint16_t offset_low;      // Lower 16 bits of handler address
    uint16_t selector;        // Code segment selector
    uint8_t  ist;             // Interrupt Stack Table
    uint8_t  type_attr;       // Type and attributes
    uint16_t offset_mid;     // Middle 16 bits of handler address
    uint32_t offset_high;    // Higher 32 bits of handler address
    uint32_t reserved;       // Reserved
} __attribute__((packed)) IDTEntry;

/* Interrupt Service Routine (ISR) - Timer Interrupt */
void timer_isr(void) {
    /* Save processor state */
    __asm__ __volatile__("pushad");  // Push all general registers

    /* Handle timer interrupt - update system clock, process scheduling */
    static int tick_count = 0;
    tick_count++;

    if (tick_count % 100 == 0) {
        printf("Timer interrupt #%d occurred\n", tick_count);
    }

    /* Send End of Interrupt (EOI) to PIC */
    outb(0x20, 0x20);  // Master PIC EOI command

    /* Restore processor state */
    __asm__ __volatile__("popad");   // Pop all general registers

    /* Return from interrupt */
    __asm__ __volatile__("iret");   // Interrupt return
}

/* System Call Handler - Example: read from file */
ssize_t sys_read(int fd, void *buf, size_t count) {
    /* Check if in user mode - security check */
    if (!is_kernel_mode()) {
        return -EACCES;  // Permission denied
    }

    /* Validate file descriptor and buffer */
    if (fd < 0 || fd >= MAX_OPEN_FILES || buf == NULL) {
        return -EINVAL;
    }

    /* Call file system driver to perform read */
    return file_system_read(current_process->file_table[fd], buf, count);
}

/* Main function to demonstrate interrupt setup */
int main() {
    printf("=== Interrupt Handler Demonstration ===\n");

    /* Simulate interrupt initialization */
    printf("Initializing Interrupt Descriptor Table...\n");
    IDTEntry idt[256];

    /* Set up timer interrupt handler */
    uint64_t handler_addr = (uint64_t)&timer_isr;
    idt[32].offset_low = handler_addr & 0xFFFF;
    idt[32].offset_mid = (handler_addr >> 16) & 0xFFFF;
    idt[32].offset_high = (handler_addr >> 32) & 0xFFFFFFFF;
    idt[32].selector = 0x08;  // Kernel code segment
    idt[32].type_attr = 0x8E; // Present, DPL=0, 32-bit interrupt gate

    printf("Timer interrupt (IRQ 0) handler registered at IDT[32]\n");
    printf("System calls and interrupts now operational\n");

    return 0;
}
